var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신이 왜 여기에 있어?","JPN":"どうしてあなたがここに？","ENG":"What are you doing here?","TWN":"你為什麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대가 범을 마주하기 전에 더 나은 계획을 논하러 왔다네.","JPN":"そなたが虎を向かえる前に、より良い計画を相談しに来たのだ。","ENG":"I came to discuss a better plan before you confront the Tiger.","TWN":"我來這裡是為了在你們面對老虎之前，討論一個更好的計畫。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지금 두 사람의 힘만으론 범을 잡는다 한들, 무사히 돌아올 수는 없을 테니 말이야.","JPN":"今の2人の力だけでは虎を倒せたとしても、無事生還することはできぬゆえ。","ENG":"Because even if the two of you manage to defeat it, you won't make it back alive.","TWN":"就算你們兩人合力能抓住老虎，也無法安全回來。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…이지수.","JPN":"……ムラサメ・シノ。","ENG":"…Lee Jisoo.","TWN":"…李智秀。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"일면식도 없는 두 사람이 함께 나타날 줄은 몰랐구나.","JPN":"面識のない2人が共に現れるとは。","ENG":"Never thought I'd see the two complete strangers show up.","TWN":"我沒想到，兩個素不相識的人會一起出現。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"범을 잡고 싶다면 우리가 돕지.","JPN":"虎を倒したいなら私たちが手伝う。","ENG":"If you want to slay the Tiger, we'll help.","TWN":"如果想抓住老虎，我們來幫忙。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"실력이 의심된다면 당장 칼을 뽑아서 시험해봐도 상관없어.","JPN":"腕を疑うのなら、今すぐ剣を抜いて直接確かめてもらっても構わない。","ENG":"And if you're not convinced, feel free to draw your sword and test me.","TWN":"如果你懷疑我們的實力，現在就可以拔劍試試看。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"부질없는 짓이에요.","JPN":"無駄なことです。","ENG":"That would be pointless.","TWN":"這是無意義的。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신이 그 검을 얼마나 잘 다루건, 짐승의 피 한 방울 섞이지 않은 사람은 범에게 생채기 하나 입힐 수 없으니까요.","JPN":"あなたがその剣をどれほど上手く扱えようが、ケモノの血を一滴も受け継いでいない人間は虎に傷の一つもつけられません。","ENG":"No matter how skilled you are with that sword, if you don't carry a drop of Beast Blood, you won't even scratch it.","TWN":"無論你的劍術有多高超，沒有一滴野獸之血的人，都無法傷害到老虎。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"걱정 마. 짐승의 피가 섞였는진 모르겠지만, 이것 하나는 확실하니까.","JPN":"問題ない。ケモノの血が流れているかは分からないが、1つだけは確かだ。","ENG":"I don't know about Beast Blood, but one thing's for sure.","TWN":"別擔心。我不知道有沒有野獸之血，但我可以肯定一件事。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나에겐 저 사람과 같은 피가 흐르고 있거든.","JPN":"私にはこの人と同じ血が流れている。","ENG":"I've got the same blood running through me as that man.","TWN":"我的身體裡流著和那個人一樣的血。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장의 피…? 그럴 리가.","JPN":"アカタツ隊長の血……？　そんな。","ENG":"Commander Myeongdal's blood…? That can't be.","TWN":"明達隊長的血…？這不可能。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"맞는 말이다, 연화야.","JPN":"その通りだ、レンカ。","ENG":"She's telling the truth, Yeonhwa.","TWN":"她說得沒錯，蓮華。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"저 아이의 몸엔 틀림없이 나와 같은 짐승의 피가 흐르고 있다.","JPN":"あの子の体には、間違いなく俺と同じケモノの血が流れている。","ENG":"That child carries the same Beast Blood as I do.","TWN":"這孩子的身體裡，確實流著和我一樣的野獸之血。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만, 명달 대장은 분명…","JPN":"しかし、アカタツ隊長は確か……","ENG":"But you said–","TWN":"但是，明達隊長明明…"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…평생을 제 핏줄 하나 없이 홀로 살아왔다고 했지.","JPN":"……一生家庭を持たずに独りで生きてきたと言ったな。","ENG":"…That I lived my whole life alone, without kin?","TWN":"…說過自己一輩子沒有任何血親，孤獨地活著。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나 지금 보고 있는 게 진실이다.","JPN":"だが、目の前にいるのは真実だ。","ENG":"And yet, what stands before you is the truth.","TWN":"然而你現在看到的才是真相。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"저 아이에겐 틀림없이 나와 같은 피가 흐르고 있으니.","JPN":"あの子には、間違いなく俺と同じ血が流れている。","ENG":"That child undoubtedly carries the same blood as I do.","TWN":"這孩子的身體裡，確實流著和我一樣的血。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"알겠습니다. 더 캐묻진 않을게요.","JPN":"分かりました。それ以上は聞きません。","ENG":"Understood. I won't ask any more questions.","TWN":"明白了。我不會再追問了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"고맙구나.","JPN":"すまんな。","ENG":"Thank you.","TWN":"謝謝你。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해서 저들을 범이 있는 사지로 데려갈 이유는 없어요.","JPN":"ですが、彼らを虎のいる死地へ連れて行く理由にはなりません。","ENG":"But that doesn't mean I'll let them walk into the jaws of death with us.","TWN":"但即便如此，也沒有理由將他們帶到老虎所在的死地。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"왜 그렇게까지 날 밀어내는 거요.","JPN":"なぜそこまで某を拒む？","ENG":"Why are you so desperate to push me away?","TWN":"你為什麼要如此地推開我？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신이 나선다고 해도 결과는 바뀌지 않을 테니까.","JPN":"あなたがいたところで、結果は変わらないからよ。","ENG":"Because your presence won't change the outcome.","TWN":"就算你出馬，結果也不會改變。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"마치 결과를 다 내다본 듯이 말하는군.","JPN":"まるで結果を知っているかのような物言いだな。","ENG":"You speak as if you already know how this ends.","TWN":"你說話的樣子，好像把一切都看透了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신이야말로 다 아는 것처럼 말하지 마.","JPN":"あなたこそ、知ったかぶりしないで。","ENG":"And you speak like you know everything.","TWN":"你才別說得好像什麼都懂。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우린 알아요.","JPN":"私たちは知ってます。","ENG":"But we do know.","TWN":"我們知道。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};